/**
 * Combines two images from data URIs into a single horizontal image.
 * @param image1DataUri The data URI of the first image.
 * @param image2DataUri The data URI of the second image.
 * @returns A promise that resolves with the data URI of the combined image.
 */ async function combineImages(image1DataUri, image2DataUri) {
    return new Promise((resolve, reject)=>{
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) {
            return reject(new Error('Could not get canvas context'));
        }
        const img1 = new Image();
        const img2 = new Image();
        let loadedImages = 0;
        const onImageLoad = ()=>{
            loadedImages++;
            if (loadedImages === 2) {
                const targetHeight = 576;
                const img1Ratio = targetHeight / img1.height;
                const img1Width = img1.width * img1Ratio;
                const img2Ratio = targetHeight / img2.height;
                const img2Width = img2.width * img2Ratio;
                canvas.width = img1Width + img2Width;
                canvas.height = targetHeight;
                ctx.drawImage(img1, 0, 0, img1Width, targetHeight);
                ctx.drawImage(img2, img1Width, 0, img2Width, targetHeight);
                resolve(canvas.toDataURL('image/jpeg'));
            }
        };
        img1.onload = onImageLoad;
        img2.onload = onImageLoad;
        img1.onerror = (e)=>reject(new Error("Image 1 failed to load."));
        img2.onerror = (e)=>reject(new Error("Image 2 failed to load."));
        img1.src = image1DataUri;
        img2.src = image2DataUri;
    });
}
// Client-side Pollo.ai video generation logic
async function generateVideoClientSide(combinedImageUri, apiKey) {
    try {
        console.log('[POLLO_CLIENT] Starting task creation...');
        const startResponse = await fetch('https://api.pollo.ai/v1/run/kling', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${apiKey}`
            },
            body: JSON.stringify({
                input: {
                    image: combinedImageUri,
                    prompt: 'make the two people in the image kiss, 4k, cinematic'
                }
            })
        });
        if (!startResponse.ok) {
            const errorData = await startResponse.json();
            console.error('[POLLO_CLIENT_ERROR] Failed to start generation:', errorData);
            return {
                error: errorData.message || `Failed to start generation. Status: ${startResponse.status}`
            };
        }
        const { id: taskId } = await startResponse.json();
        console.log(`[POLLO_CLIENT] Task created with ID: ${taskId}`);
        let pollCount = 0;
        const maxPolls = 60; // 5 minutes timeout (60 * 5s)
        while(pollCount < maxPolls){
            pollCount++;
            await new Promise((resolve)=>setTimeout(resolve, 5000)); // Wait 5 seconds
            console.log(`[POLLO_CLIENT] Polling task ${taskId} (Attempt ${pollCount})`);
            const statusResponse = await fetch(`https://api.pollo.ai/v1/task/${taskId}`, {
                headers: {
                    'Authorization': `Bearer ${apiKey}`
                }
            });
            if (!statusResponse.ok) {
                console.warn(`[POLLO_CLIENT_WARN] Polling failed with status: ${statusResponse.status}`);
                continue;
            }
            const statusData = await statusResponse.json();
            if (statusData.status === 'success') {
                console.log('[POLLO_CLIENT] Task succeeded:', statusData);
                if (statusData.output && statusData.output.video) {
                    return {
                        videoUrl: statusData.output.video
                    };
                } else {
                    return {
                        error: 'Generation succeeded but no video URL was returned.'
                    };
                }
            } else if (statusData.status === 'failed') {
                console.error('[POLLO_CLIENT_ERROR] Task failed:', statusData);
                return {
                    error: statusData.output?.message || 'Video generation failed.'
                };
            }
        }
        return {
            error: 'Video generation timed out.'
        };
    } catch (error) {
        console.error('[POLLO_CLIENT_FATAL] A fatal error occurred during client-side generation:', error);
        return {
            error: error instanceof Error ? error.message : 'An unknown network error occurred.'
        };
    }
}
